```c
// In codegen_emit_executable.c

int emit_executable(LLVMModuleRef module, const char* output_path, 
                   CompilerOptions* options) {
    // Initialize target machine with appropriate triple and features
    char* error = NULL;
    LLVMTargetRef target = NULL;

    if (LLVMGetTargetFromTriple(options->target_triple, &target, &error)) {
        fprintf(stderr, "Error getting target: %s\n", error);
        LLVMDisposeMessage(error);
        return 1;
    }

    // Create target machine with appropriate options
    LLVMTargetMachineRef target_machine = LLVMCreateTargetMachine(
        target,
        options->target_triple,
        options->cpu,
        options->features,
        options->opt_level,
        LLVMRelocDefault,
        LLVMCodeModelDefault);

    // Set data layout for the module
    LLVMSetDataLayout(module, LLVMGetDataLayoutStr(target_machine));

    // Generate object file
    if (LLVMTargetMachineEmitToFile(target_machine, module, 
                                   "temp.o", LLVMObjectFile, &error)) {
        fprintf(stderr, "Error emitting object file: %s\n", error);
        LLVMDisposeMessage(error);
        LLVMDisposeTargetMachine(target_machine);
        return 1;
    }

    // Link object file with runtime libraries to create executable
    if (!link_executable("temp.o", output_path, options)) {
        fprintf(stderr, "Error linking executable\n");
        LLVMDisposeTargetMachine(target_machine);
        return 1;
    }

    // Clean up
    LLVMDisposeTargetMachine(target_machine);
    return 0;
}

// Platform-specific linking implementation
bool link_executable(const char* object_file, const char* output_path,
                    CompilerOptions* options) {
    // Platform-specific linking logic
    #ifdef _WIN32
        return link_executable_windows(object_file, output_path, options);
    #elif defined(__APPLE__)
        return link_executable_macos(object_file, output_path, options);
    #else
        return link_executable_linux(object_file, output_path, options);
    #endif
}
```

